queries.sparql:
PREFIX : <http://ambrosia.example.org/streamingservice#>
PREFIX p: <http://ambrosia.example.org/streamingservice/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?payment_type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasPayments ?child ; p:hasStreamings ?parent . } GROUP BY ?child }
  ?child p:payment_type ?payment_type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Streamings } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/streamingservice#>
PREFIX p: <http://ambrosia.example.org/streamingservice/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?streaming_id ?payment_type WHERE {
  ?streamings_payments a :Streamings_Payments .
  ?streamings a :Streamings .
  ?streamings_payments p:hasStreamings ?streamings .
  ?payments a :Payments .
  ?streamings_payments p:hasPayments ?payments .
  ?streamings p:streaming_id ?streaming_id .
  ?payments p:payment_type ?payment_type .
} }
  collective: { SELECT ?payment_type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasPayments ?child ; p:hasStreamings ?parent . } GROUP BY ?child }
  ?child p:payment_type ?payment_type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Streamings } }
  FILTER(?nf = ?total)
} }
}
